import { Routes } from '@angular/router';
import { HomeComponent } from './components/home/home.component';
import { CoursesComponent } from './components/courses/courses.component';
import { CourseDetailComponent } from './components/course-detail/course-detail.component';
import { ExamsComponent } from './components/exams/exams.component';
import { ExamDetailComponent } from './components/exam-detail/exam-detail.component';
import { LiveSessionsComponent } from './components/live-sessions/live-sessions.component';
import { DashboardComponent } from './components/dashboard/dashboard.component';
import { LoginComponent } from './components/login/login.component';
import { RegisterComponent } from './components/register/register.component';
import { authGuard } from './guards/auth.guard';

export const routes: Routes = [
  { path: '', component: HomeComponent, title: 'EduPlatform - Learn Anything, Anytime, Anywhere' },
  { path: 'courses', component: CoursesComponent, title: 'Course Catalog - EduPlatform' },
  { path: 'courses/:id', component: CourseDetailComponent, title: 'Course Details - EduPlatform' },
  { path: 'exams', component: ExamsComponent, title: 'Practice Exams - EduPlatform' },
  { path: 'exams/:id', component: ExamDetailComponent, title: 'Exam Details - EduPlatform' },
  { path: 'live-sessions', component: LiveSessionsComponent, title: 'Live Sessions - EduPlatform' },
  { path: 'dashboard', component: DashboardComponent, canActivate: [authGuard], title: 'Dashboard - EduPlatform' },
  { path: 'login', component: LoginComponent, title: 'Sign In - EduPlatform' },
  { path: 'register', component: RegisterComponent, title: 'Join EduPlatform' },
  { path: '**', redirectTo: '' }
];
